import React, { useEffect, useRef, useState } from 'react';
import io from 'socket.io-client';
import Peer from 'simple-peer';

const VideoCall = ({ roomId, userId, onLeave, serverUrl }) => {
  const [peers, setPeers] = useState([]);
  const [localStream, setLocalStream] = useState(null);
  const [remoteStreams, setRemoteStreams] = useState(new Map());
  const [isAudioEnabled, setIsAudioEnabled] = useState(true);
  const [isVideoEnabled, setIsVideoEnabled] = useState(true);
  const [connectionStatus, setConnectionStatus] = useState('connecting');
  const [socketId, setSocketId] = useState('');
  const [hasJoinedRoom, setHasJoinedRoom] = useState(false); // Track if we've joined
  
  const socketRef = useRef();
  const peersRef = useRef([]);
  const localVideoRef = useRef();
  const remoteVideosRef = useRef(new Map());
  const pendingOffersRef = useRef([]);
  const pendingParticipantsRef = useRef([]); // Store participants who joined while we were busy

  useEffect(() => {
    console.log('Initializing VideoCall with roomId:', roomId, 'userId:', userId);
    
    // Connect to signaling server
    socketRef.current = io(serverUrl, {
      transports: ['websocket', 'polling'],
      reconnectionAttempts: 5,
      reconnectionDelay: 1000,
      timeout: 20000,
      forceNew: true
    });

    // Socket connection event handlers
    socketRef.current.on('connect', () => {
      console.log('✅ Socket connected with ID:', socketRef.current.id);
      setSocketId(socketRef.current.id);
      setConnectionStatus('connected');
      
      // STEP 1: Get camera/microphone FIRST
      console.log('📷 STEP 1: Requesting camera access...');
      const constraints = {
        video: {
          width: { ideal: 640 },
          height: { ideal: 480 },
          frameRate: { ideal: 30 },
          facingMode: "user"
        },
        audio: {
          echoCancellation: true,
          noiseSuppression: true
        }
      };

      navigator.mediaDevices.getUserMedia(constraints)
        .then(stream => {
          console.log('✅ STEP 2: Got local stream successfully');
          setLocalStream(stream);
          if (localVideoRef.current) {
            localVideoRef.current.srcObject = stream;
          }

          // STEP 3: NOW join the room (only after camera is ready)
          console.log('✅ STEP 3: Camera ready, joining room now...');
          socketRef.current.emit('join-room', { roomId, userId });
          setHasJoinedRoom(true);
          
          // STEP 4: Process any offers that came in while getting camera
          console.log('📋 Checking pending offers:', pendingOffersRef.current.length);
          pendingOffersRef.current.forEach(({ offer, from }) => {
            console.log('Creating peer for queued offer from:', from);
            createPeer(from, false, offer);
          });
          pendingOffersRef.current = [];

          // STEP 5: Process any participants that joined while getting camera
          console.log('👥 Checking pending participants:', pendingParticipantsRef.current.length);
          pendingParticipantsRef.current.forEach(participant => {
            if (participant.socketId !== socketRef.current.id) {
              console.log('Creating peer for pending participant:', participant);
              createPeer(participant.socketId, true);
            }
          });
          pendingParticipantsRef.current = [];
        })
        .catch(error => {
          console.error('❌ Error accessing media devices:', error);
          setConnectionStatus('error');
          
          if (error.name === 'NotAllowedError') {
            alert('Please allow camera and microphone access');
          } else if (error.name === 'NotFoundError') {
            alert('No camera or microphone found');
          } else {
            alert(`Could not access camera: ${error.message}`);
          }
        });
    });

    // Handle room-joined event
    socketRef.current.on('room-joined', ({ participants, isHost }) => {
      console.log('🏠 Room joined! Participants:', participants);
      
      if (!localStream) {
        // If we don't have stream yet, save participants for later
        console.log('⏳ No stream yet, saving participants for later');
        pendingParticipantsRef.current = participants;
        return;
      }

      // Create peers for existing participants
      participants.forEach(participant => {
        if (participant.socketId !== socketRef.current.id) {
          console.log('Creating peer for participant:', participant);
          createPeer(participant.socketId, true);
        }
      });
    });

    // Handle user-connected event
    socketRef.current.on('user-connected', ({ userId, socketId }) => {
      console.log('👤 User connected:', userId);
      
      if (!localStream) {
        // If we don't have stream yet, ignore (they'll send us an offer later)
        console.log('⏳ No stream yet, ignoring user-connected');
        return;
      }
      
      if (socketId !== socketRef.current.id) {
        createPeer(socketId, false);
      }
    });

    // Handle offer (keep this the same)
    socketRef.current.on('offer', ({ offer, from }) => {
      console.log('📞 Received offer from:', from);
      
      if (!localStream) {
        console.log('⏳ No stream yet, queueing offer');
        pendingOffersRef.current.push({ offer, from });
        return;
      }
      
      const peerExists = peersRef.current.find(p => p.peerID === from);
      if (!peerExists) {
        createPeer(from, false, offer);
      }
    });

    // Handle answer
    socketRef.current.on('answer', ({ answer, from }) => {
      console.log('📞 Received answer from:', from);
      const peer = peersRef.current.find(p => p.peerID === from);
      if (peer) {
        peer.peer.signal(answer);
      }
    });

    // Handle ICE candidate
    socketRef.current.on('ice-candidate', ({ candidate, from }) => {
      console.log('📞 Received ICE candidate from:', from);
      const peer = peersRef.current.find(p => p.peerID === from);
      if (peer && candidate) {
        peer.peer.signal(candidate);
      }
    });

    // Handle user disconnected
    socketRef.current.on('user-disconnected', ({ socketId, userId }) => {
      console.log('👤 User disconnected:', userId);
      
      const peerIndex = peersRef.current.findIndex(p => p.peerID === socketId);
      if (peerIndex !== -1) {
        peersRef.current[peerIndex].peer.destroy();
        peersRef.current.splice(peerIndex, 1);
      }
      
      const videoElement = remoteVideosRef.current.get(socketId);
      if (videoElement) {
        videoElement.srcObject = null;
        videoElement.remove();
        remoteVideosRef.current.delete(socketId);
      }

      setPeers(peersRef.current.map(p => p.peerID));
      setRemoteStreams(new Map(remoteVideosRef.current));
    });

    // Cleanup
    return () => {
      console.log('Cleaning up...');
      peersRef.current.forEach(peer => peer.peer.destroy());
      if (localStream) {
        localStream.getTracks().forEach(track => track.stop());
      }
      if (socketRef.current) {
        socketRef.current.disconnect();
      }
    };
  }, [roomId, userId, serverUrl]);

  const createPeer = (targetSocketId, initiator, offer = null) => {
    if (!localStream) {
      console.log('Cannot create peer - no local stream');
      return;
    }

    console.log('Creating peer for:', targetSocketId, 'initiator:', initiator);

    const peer = new Peer({
      initiator: initiator,
      stream: localStream,
      trickle: true,
      config: {
        iceServers: [
          { urls: 'stun:stun.l.google.com:19302' },
          { urls: 'stun:stun1.l.google.com:19302' }
        ]
      }
    });

    peersRef.current.push({
      peerID: targetSocketId,
      peer: peer
    });

    setPeers(peersRef.current.map(p => p.peerID));

    peer.on('signal', signal => {
      console.log('📡 Signal from peer:', targetSocketId, signal.type);
      
      if (initiator && !offer) {
        socketRef.current.emit('offer', {
          offer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else if (offer && signal.type === 'answer') {
        socketRef.current.emit('answer', {
          answer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else if (signal.type === 'candidate') {
        socketRef.current.emit('ice-candidate', {
          candidate: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      }
    });

    peer.on('stream', stream => {
      console.log('🎥 Received stream from peer:', targetSocketId);
      
      let videoElement = remoteVideosRef.current.get(targetSocketId);
      if (!videoElement) {
        videoElement = document.createElement('video');
        videoElement.id = `remote-video-${targetSocketId}`;
        videoElement.autoplay = true;
        videoElement.playsInline = true;
        videoElement.className = "w-full h-full object-cover";
        remoteVideosRef.current.set(targetSocketId, videoElement);
      }
      
      videoElement.srcObject = stream;
      setRemoteStreams(new Map(remoteVideosRef.current));
    });

    peer.on('connect', () => {
      console.log('✅ Peer connected with:', targetSocketId);
    });

    peer.on('error', err => {
      console.error('❌ Peer error:', err);
    });

    if (offer) {
      console.log('Signaling offer to peer');
      peer.signal(offer);
    }
  };

  // Rest of your component (toggleAudio, toggleVideo, return statement) remains the same
  // ...

  return (
    // Your existing JSX remains exactly the same
    <div className="space-y-4">
      {/* ... */}
    </div>
  );
};

export default VideoCall;
